use crate::state::SequenceRecord;
use bio::io::fasta;
use std::io::BufReader;
use std::fs::File;

pub fn load_file(path: &str) -> anyhow::Result<Vec<SequenceRecord>> {
    let file = File::open(path)?;
    let reader = fasta::Reader::new(BufReader::new(file));
    let mut records = Vec::new();

    for result in reader.records() {
        let record = result?;
        records.push(SequenceRecord::new(
            record.id().to_string(),
            record.desc().unwrap_or("").to_string(),
            record.seq().to_vec(),
        ));
    }
    Ok(records)
}

pub fn demo_sequences() -> Vec<SequenceRecord> {
    vec![
        SequenceRecord::new("NC_001802.1".into(), "HIV-1 genome".into(), b"".to_vec()),
        SequenceRecord::new("AF086833.2".into(), "Ebola virus VP40".into(), b"".to_vec()),
    ]
}